#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int prev, cur;
        if(N>0){
            scanf("%d", &prev);
            printf("%d", prev);
            for(int i=1;i<N;i++){
                scanf("%d", &cur);
                if(cur!=prev){
                    printf(" %d", cur);
                    prev = cur;
                }
            }
        }
        printf("\n");
    }
    return 0;
}

